@@ -1338,18 +1338,53 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       V2 = X;
   }

-  if (V1 != V2)
-    return nullptr;
-
+  // Look through and with a mask on V1 or V2. This handles patterns like:
+  //   x == C1 || (x & Mask) == C2
+  // where (x & Mask) == C2 defines a contiguous range of values.
+  // For OR, we need EQ predicates. For AND, we need NE predicates.
+  const APInt *Mask1 = nullptr, *Mask2 = nullptr;
+  if (V1 != V2) {
+    Value *X;
+    // Only look through and when the predicate is EQ (for OR) or NE (for AND).
+    // This ensures we're dealing with a range that can be unioned/intersected.
+    // Also require one-use to avoid increasing instruction count.
+    if (!IsAnd && Pred1 == ICmpInst::ICMP_EQ &&
+        match(V1, m_OneUse(m_And(m_Value(X), m_APInt(Mask1)))))
+      V1 = X;
+    if (!IsAnd && Pred2 == ICmpInst::ICMP_EQ &&
+        match(V2, m_OneUse(m_And(m_Value(X), m_APInt(Mask2)))))
+      V2 = X;
+  }
   ConstantRange CR1 = ConstantRange::makeExactICmpRegion(
       IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
   if (Offset1)
     CR1 = CR1.subtract(*Offset1);
+  // If we looked through an and with a mask, expand the range to account for
+  // the bits that were masked out. For (x & Mask) == C, the valid values of x
+  // are those where (x & Mask) == C, which means x can be C + any value in
+  // the range [0, ~Mask + 1).
+  if (Mask1) {
+    APInt LowBits = ~(*Mask1) + 1;
+    if (LowBits.isPowerOf2()) {
+      // The mask clears LowBits trailing bits, so the range is [C, C + LowBits)
+      ConstantRange MaskedCR(APInt(C1->getBitWidth(), 0),
+                             APInt(C1->getBitWidth(), LowBits.getZExtValue()));
+      CR1 = MaskedCR.add(*C1);
+    }
+  }

   ConstantRange CR2 = ConstantRange::makeExactICmpRegion(
       IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
   if (Offset2)
     CR2 = CR2.subtract(*Offset2);
+  if (Mask2) {
+    APInt LowBits = ~(*Mask2) + 1;
+    if (LowBits.isPowerOf2()) {
+      ConstantRange MaskedCR(APInt(C2->getBitWidth(), 0),
+                             APInt(C2->getBitWidth(), LowBits.getZExtValue()));
+      CR2 = MaskedCR.add(*C2);
+    }
+  }

   Type *Ty = V1->getType();
   Value *NewV = V1;
